parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const config = body.config || {};

if (!tenantId || !automationId) {
  return [{ json: { valid: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, config, valid: true } }];

const catalogRow = $('04. Chercher catalogue + tenant').first().json;
const existingPurchase = $('05. Verifier achat existant').first().json;
const data = $('02. Valider donnees').first().json;

if (!catalogRow || !catalogRow.code) {
  return [{ json: { valid: false, error: 'Automatisation ou tenant introuvable' } }];
}

const tenantName = catalogRow.tenant_name || 'Client';
const automationCode = catalogRow.code;
const automationNom = catalogRow.nom;
const setupPrice = catalogRow.setup_price || 0;
const monthlyPrice = catalogRow.monthly_price || 0;
const n8nFolderName = `[Client] ${tenantName}`;
const existingFolderId = existingPurchase?.n8n_folder_id || null;
const existingWorkflowIds = existingPurchase?.n8n_workflow_ids || [];

// Construire le workflow a creer pour ce client
const workflow = {
  name: `[${tenantName}] ${automationNom}`,
  nodes: [
    {
      parameters: {
        rule: { interval: [{ field: 'hours', hoursInterval: 24 }] }
      },
      id: 'schedule-node',
      name: 'Declencheur',
      type: 'n8n-nodes-base.scheduleTrigger',
      typeVersion: 1.2,
      position: [250, 300]
    },
    {
      parameters: {
        jsCode: `// Automatisation: ${automationNom}\n// Client: ${tenantName}\n// Code: ${automationCode}\n// Cree automatiquement par TalosPrimes\nconst now = new Date().toISOString();\nreturn [{ json: { client: '${tenantName}', automation: '${automationCode}', timestamp: now, status: 'ok' } }];`
      },
      id: 'code-node',
      name: 'Traitement',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [470, 300]
    }
  ],
  connections: {
    'Declencheur': { main: [[{ node: 'Traitement', type: 'main', index: 0 }]] }
  },
  settings: { executionOrder: 'v1' }
};

return [{ json: {
  valid: true,
  tenantId: data.tenantId,
  automationId: data.automationId,
  automationCode,
  automationNom,
  tenantName,
  setupPrice,
  monthlyPrice,
  config: data.config,
  n8nFolderName,
  existingFolderId,
  existingWorkflowIds,
  workflow
} }];

const response = $input.first().json;
const workflowId = response.id || null;
const workflowName = response.name || null;
const data = $('06. Construire workflow').first().json;
const existingFolderId = data.existingFolderId;
const canMove = !!(existingFolderId && workflowId);

// Fusionner le nouveau workflowId avec les existants
const existingIds = data.existingWorkflowIds || [];
const allWorkflowIds = workflowId ? [...existingIds, workflowId] : existingIds;

return [{ json: {
  workflowId,
  workflowName,
  allWorkflowIds,
  folderId: existingFolderId,
  folderName: data.n8nFolderName,
  tenantId: data.tenantId,
  automationId: data.automationId,
  automationCode: data.automationCode,
  automationNom: data.automationNom,
  tenantName: data.tenantName,
  setupPrice: data.setupPrice,
  monthlyPrice: data.monthlyPrice,
  config: data.config,
  canMove,
  status: workflowId ? 'workflow_cree' : 'erreur_creation'
} }];

const data = $('09. Verifier creation').first().json;
let movedToFolder = false;

try {
  const moveResult = $('11. Deplacer dans dossier').first();
  movedToFolder = moveResult && !moveResult.json?.message?.includes('error');
} catch {
  // pas de deplacement effectue
}

return [{ json: {
  ...data,
  movedToFolder
} }];
